    prev = None
    rows = []
    for _ in range(min(max_rows, h)):
        if i + 1 + bytes_per_row > len(produced):
            break
        filter_type = produced[i]
        i += 1
        raw = produced[i:i+bytes_per_row]
        i += bytes_per_row

